        case "openCamera":
            openCamera(body)
        case "openPhotoLibrary":
            openPhotoLibrary()
        default:
            break
        }
    }
    
    private func requestCameraPermission() {
        AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
            DispatchQueue.main.async {
                self?.sendMessageToWeb(type: "cameraPermission", data: ["granted": granted])
            }
        }
    }
    
    private func openCamera(_ body: [String: Any]) {
        let authStatus = AVCaptureDevice.authorizationStatus(for: .video)
        
        guard authStatus == .authorized else {
            sendMessageToWeb(type: "cameraError", data: ["error": "Permission denied"])
            return
        }
        
        let picker = UIImagePickerController()
        picker.delegate = self
        picker.sourceType = .camera
        
        if let allowsEditing = body["allowsEditing"] as? Bool {
            picker.allowsEditing = allowsEditing
        }
        
        if let mediaTypes = body["mediaTypes"] as? [String] {
            picker.mediaTypes = mediaTypes
        }
        
        present(picker, animated: true)
    }
    
    private func openPhotoLibrary() {
        let picker = UIImagePickerController()
        picker.delegate = self
        picker.sourceType = .photoLibrary
        present(picker, animated: true)
    }
    
