        switch action {
        case "requestPermission":
            requestPushNotificationPermission()
        case "getDeviceToken":
            getDeviceToken()
        default:
            break
        }
    }
    
    private func requestPushNotificationPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.sendMessageToWeb(type: "pushNotificationError", data: ["error": error.localizedDescription])
                } else {
                    self?.sendMessageToWeb(type: "pushNotificationPermission", data: ["granted": granted])
                    if granted {
                        UIApplication.shared.registerForRemoteNotifications()
                    }
                }
            }
        }
    }
    
    private func getDeviceToken() {
        if let token = UserDefaults.standard.string(forKey: "deviceToken") {
            sendMessageToWeb(type: "deviceToken", data: ["token": token])
        } else {
            sendMessageToWeb(type: "deviceToken", data: ["token": ""])
