                self?.sendMessageToWeb(type: "purchaseError", data: ["error": error ?? "Unknown error"])
            }
        }
    }
    
    private func restorePurchases() {
        InAppPurchaseManager.shared.restorePurchases { [weak self] success, error in
            if success {
                self?.sendMessageToWeb(type: "restoreSuccess", data: [:])
            } else {
                self?.sendMessageToWeb(type: "restoreError", data: ["error": error ?? "Unknown error"])
            }
        }
    }
    
    private func fetchProducts(productIds: [String]) {
        InAppPurchaseManager.shared.fetchProducts(productIds: productIds) { [weak self] products, error in
            if let products = products {
                let productsData = products.map { product in
                    return [
                        "productId": product.productIdentifier,
                        "price": product.price.doubleValue,
                        "localizedPrice": product.localizedPrice,
                        "title": product.localizedTitle,
