                shareContent(text: text, url: body["url"] as? String)
            }
        case "vibrate":
            UINotificationFeedbackGenerator().notificationOccurred(.success)
        case "getBatteryLevel":
            UIDevice.current.isBatteryMonitoringEnabled = true
            let batteryLevel = UIDevice.current.batteryLevel
            sendMessageToWeb(type: "batteryLevel", data: ["level": batteryLevel])
        case "getDeviceInfo":
            getDeviceInfo()
        default:
            break
        }
    }
    
    private func shareContent(text: String, url: String?) {
        var items: [Any] = [text]
        if let urlString = url, let shareURL = URL(string: urlString) {
            items.append(shareURL)
