extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        picker.dismiss(animated: true)
        
        var imageData: Data?
        
        if let editedImage = info[.editedImage] as? UIImage {
            imageData = editedImage.jpegData(compressionQuality: 0.8)
        } else if let originalImage = info[.originalImage] as? UIImage {
            imageData = originalImage.jpegData(compressionQuality: 0.8)
        }
        
        if let data = imageData {
            let base64String = data.base64EncodedString()
            sendMessageToWeb(type: "cameraResult", data: ["image": base64String])
        }
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        picker.dismiss(animated: true)
        sendMessageToWeb(type: "cameraCancelled", data: [:])
    }
}

class InAppPurchaseManager: NSObject {
    static let shared = InAppPurchaseManager()
    
    private var productRequest: SKProductsRequest?
    private var products: [SKProduct] = []
    private var purchaseCompletion: ((Bool, String?) -> Void)?
    private var restoreCompletion: ((Bool, String?) -> Void)?
    private var productsCompletion: (([SKProduct]?, String?) -> Void)?
    
    override private init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }
    
    func fetchProducts(productIds: [String], completion: @escaping ([SKProduct]?, String?) -> Void) {
        productsCompletion = completion
        let request = SKProductsRequest(productIdentifiers: Set(productIds))
        request.delegate = self
        request.start()
        productRequest = request
    }
    
    func purchase(productId: String, completion: @escaping (Bool, String?) -> Void) {
        guard let product = products.first(where: { $0.productIdentifier == productId }) else {
            completion(false, "Product not found")
            return
        }
        
        purchaseCompletion = completion
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }
    
    func restorePurchases(completion: @escaping (Bool, String?) -> Void) {
        restoreCompletion = completion
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
}

extension InAppPurchaseManager: SKProductsRequestDelegate {
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        products = response.products
        productsCompletion?(products, nil)
        productsCompletion = nil
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        productsCompletion?(nil, error.localizedDescription)
        productsCompletion = nil
    }
}

extension InAppPurchaseManager: SKPaymentTransactionObserver {
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                SKPaymentQueue.default().finishTransaction(transaction)
                purchaseCompletion?(true, nil)
                purchaseCompletion = nil
            case .failed:
                SKPaymentQueue.default().finishTransaction(transaction)
                purchaseCompletion?(false, transaction.error?.localizedDescription)
                purchaseCompletion = nil
            case .restored:
                SKPaymentQueue.default().finishTransaction(transaction)
            case .deferred, .purchasing:
                break
            @unknown default:
                break
            }
        }
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        restoreCompletion?(true, nil)
        restoreCompletion = nil
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        restoreCompletion?(false, error.localizedDescription)
        restoreCompletion = nil
    }
}

extension SKProduct {
    var localizedPrice: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.locale = priceLocale
        return formatter.string(from: price) ?? ""
    }
}